SponStencilId spon_l0_stencil_for_opcode(uint32_t opcode) {
  return opcode < 256 ? spon_l0[opcode] : 0;
}

static int actual_slot_lookup(const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots, uint16_t op_idx, uint8_t field_kind, uint8_t *out_slot) {
  for (uint32_t i = 0; i < n_actual_slots; i++) {
    if (actual_slots[i].op_idx == op_idx && actual_slots[i].field_kind == field_kind) { *out_slot = actual_slots[i].logical_slot; return 1; }
  }
  return 0;
}

static int stencil_matches_actual_slots(const SponStencilDesc *f, const SponBankShard *s, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!actual_slots) return 1;
  uint8_t logical_seen[256] = {0};
  uint8_t logical_to_actual[256] = {0};
  uint8_t actual_seen[256] = {0};
  uint8_t actual_to_logical[256] = {0};
  const SponSlotMapEntry *sms = s->slotmaps + f->slotmap_start;
  for (uint32_t i = 0; i < f->n_slotmaps; i++) {
    uint8_t actual = 0;
    uint8_t logical = sms[i].logical_slot;
    if (!actual_slot_lookup(actual_slots, n_actual_slots, (uint16_t)(pc + sms[i].op_idx), sms[i].field_kind, &actual)) return 0;
    if (actual >= 8) return 0;
    if (logical_seen[logical] && logical_to_actual[logical] != actual) return 0;
    logical_seen[logical] = 1;
    logical_to_actual[logical] = actual;
    if (actual_seen[actual] && actual_to_logical[actual] != logical) return 0;
    actual_seen[actual] = 1;
    actual_to_logical[actual] = logical;
  }
  return 1;
}

static SponFactSig remap_stencil_sig(const SponStencilDesc *f, const SponBankShard *s, SponFactSig sig, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!f || !actual_slots) return sig;
  uint8_t map[8] = {0};
  uint8_t seen[8] = {0};
  const SponSlotMapEntry *sms = s->slotmaps + f->slotmap_start;
  for (uint32_t i = 0; i < f->n_slotmaps; i++) {
    uint8_t logical = sms[i].logical_slot;
    uint8_t actual = 0;
    if (logical >= 8) continue;
    if (!actual_slot_lookup(actual_slots, n_actual_slots, (uint16_t)(pc + sms[i].op_idx), sms[i].field_kind, &actual)) continue;
    if (actual < 8) { seen[logical] = 1; map[logical] = actual; }
  }
  SponFactSig out = sig & 0x7f00000000000000ULL;
  static const uint8_t bases[] = {0,8,16,24,32,40,48};
  for (uint32_t bi = 0; bi < sizeof(bases); bi++) {
    uint8_t base = bases[bi];
    for (uint8_t slot = 0; slot < 8; slot++) {
      SponFactSig bit = ((SponFactSig)1) << (base + slot);
      if ((sig & bit) == 0) continue;
      uint8_t dst = seen[slot] ? map[slot] : slot;
      if (dst < 8) out |= ((SponFactSig)1) << (base + dst);
    }
  }
  return out;
}

static SponFactSig apply_transfer(SponFactSig facts, const SponStencilDesc *f, const SponBankShard *s, uint32_t pc, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots) {
  if (!f) return facts;
  SponFactSig killed = remap_stencil_sig(f, s, f->killed_sig, pc, actual_slots, n_actual_slots);
  SponFactSig produced = remap_stencil_sig(f, s, f->produced_sig, pc, actual_slots, n_actual_slots);
  SponFactSig checked = remap_stencil_sig(f, s, f->checked_sig, pc, actual_slots, n_actual_slots);
  facts &= ~killed;
  facts |= produced;
  facts |= checked;
  return facts;
}

static const SponStencilChoice *select_flow_impl(const uint32_t *bc, uint32_t start, uint32_t end, SponFactSig entry_sig, SponFactSig observed_sig, uint16_t required_stencil_flags, const SponSlotMapEntry *actual_slots, uint32_t n_actual_slots, uint32_t *out_n, SponSelectStats *stats) {
  static __thread SponStencilChoice choices[4096];
  uint32_t n = 0;
  uint32_t pc = start;
  uint64_t probes = 0, checks = 0;
  SponFactSig facts = entry_sig;
  while (pc < end && n < 4096) {
    SponStencilId chosen = 0;
    const SponStencilDesc *chosen_f = NULL;
    const SponBankShard *chosen_s = NULL;
    uint32_t chosen_len = 1;
    SponFactSig available_sig = observed_sig | facts;
    for (int len = 4; len >= 1; len--) {
      if (pc + (uint32_t)len > end) continue;
      probes++;
      const PatternEntry *pe = find_pattern(make_pattern_key(bc, pc, (uint32_t)len));
      if (!pe) continue;
      for (uint32_t i = 0; i < pe->count; i++) {
        checks++;
        SponStencilId fid = spon_candidates[pe->start + i];
        const SponBankShard *s = find_shard(fid);
        const SponStencilDesc *f = spon_get_stencil(fid);
        if (!s || !f) continue;
        if ((f->flags & required_stencil_flags) != required_stencil_flags) continue;
        if (!stencil_matches_actual_slots(f, s, pc, actual_slots, n_actual_slots)) continue;
        SponFactSig fsel = remap_stencil_sig(f, s, f->selector_sig, pc, actual_slots, n_actual_slots);
        SponFactSig freq = remap_stencil_sig(f, s, f->required_sig, pc, actual_slots, n_actual_slots);
        if (((fsel & ~available_sig) == 0) && ((freq & ~facts) == 0)) { chosen = fid; chosen_len = (uint32_t)len; chosen_f = f; chosen_s = s; break; }
      }
      if (chosen) break;
    }
    if (!chosen) {
      chosen = spon_l0_stencil_for_opcode(bc[pc] & 0xffu);
      chosen_f = spon_get_stencil(chosen);
      chosen_s = find_shard(chosen);
      chosen_len = 1;
      if (!chosen_f || ((chosen_f->flags & required_stencil_flags) != required_stencil_flags)) break;
    }
    choices[n].stencil_id = chosen;
    choices[n].pc_start = pc;
    choices[n].pc_end = pc + chosen_len;
    n++;
    facts = apply_transfer(facts, chosen_f, chosen_s, pc, actual_slots, n_actual_slots);
    pc += chosen_len;
  }
  if (out_n) *out_n = n;
  if (stats) { stats->pattern_probes = probes; stats->candidate_checks = checks; stats->choices = n; }
  return choices;
}

